code = """import json
import os

# Load all articles from file
file_path = locals().get('var_functions.query_db:40')
all_articles = []

if file_path and os.path.exists(file_path):
    with open(file_path, 'r') as f:
        all_articles = json.load(f)

# Define sports keywords
sports_keywords = [
    'sport', 'sports', 'football', 'soccer', 'basketball', 'baseball', 'tennis',
    'golf', 'hockey', 'cricket', 'rugby', 'olympics', 'athlete', 'athletic',
    'championship', 'tournament', 'league', 'playoff', 'final', 'medal', 'coach',
    'player', 'team', 'game', 'match', 'race', 'racing', 'nba', 'nfl', 'mlb',
    'nhl', 'madden', 'espn', 'world cup', 'super bowl'
]

# Find sports articles and collect details
sports_articles = []
for article in all_articles:
    title = article.get('title', '').lower()
    desc = article.get('description', '').lower()
    text = title + ' ' + desc
    
    if any(keyword in text for keyword in sports_keywords):
        description = article.get('description', '')
        sports_articles.append({
            'title': article.get('title'),
            'desc_length': len(description),
            'description_snippet': description[:100] + '...' if len(description) > 100 else description
        })

# Debug: Check what sports articles were found
if sports_articles:
    # Sort by description length to find the longest
    sorted_articles = sorted(sports_articles, key=lambda x: x['desc_length'], reverse=True)
    
    result = {
        'count': len(sports_articles),
        'longest_title': sorted_articles[0]['title'],
        'longest_length': sorted_articles[0]['desc_length'],
        'top_3': sorted_articles[:3]
    }
else:
    result = {'error': 'No sports articles found'}

print('__RESULT__:')
print(json.dumps(result))"""

